choose.when:
AND (p.created_by_user_id = #{scope.userId} OR EXISTS (
  SELECT 1 FROM business_application a
  WHERE a.target_person_id = p.person_id
    AND a.applicant_user_id = #{scope.userId}
))

AND (p.created_department_id = #{scope.departmentId} OR EXISTS (
  SELECT 1 FROM business_application a
  WHERE a.target_person_id = p.person_id
    AND a.applicant_department_id = #{scope.departmentId}
))
